<template>
  <section class="section">
    <div class="modal" :class="{'is-active': !!error}">
      <div class="modal-background" @click="handleError"></div>
      <div class="modal-content">
        <article class="message is-danger">
          <div class="message-header">
            <p>Login Error</p>
            <button class="delete" aria-label="delete" @click="handleError"></button>
          </div>
          <div class="message-body">
            {{ error }}
          </div>
        </article>
      </div>
      <button class="modal-close is-large" aria-label="close" @click="handleError"></button>
    </div>
    <div class="container">
      <div v-if="isLoading">
        <base-spinner></base-spinner>
      </div>
      <div class="columns is-centered">
        <div class="column is-5-tablet is-5-desktop is-4-widescreen">
          <div class="box">
            <form @submit.prevent="doLogin">
              <div class="field">
                <label class="label" for="username">Username</label>
                <div class="control has-icons-left">
                  <input class="input" id="username" type="text" placeholder="Username" ref="userInput" v-model.trim="username">
                  <span class="icon is-small is-left">
                <svg-icon type="mdi" :path="userIcon">&nbsp;</svg-icon>
              </span>
                </div>
              </div>
              <div class="field">
                <label class="label" for="password">Password</label>
                <div class="control has-icons-left">
                  <input class="input" id="password" type="password" v-model.trim="password">
                  <span class="icon is-small is-left">
                    <svg-icon type="mdi" :path="passwordIcon">&nbsp;</svg-icon>
                  </span>
                </div>
              </div>
              <article class="message is-danger" v-if="!formIsValid">
                <div class="message-body">
                  Please make sure to enter a username and password. Neither of them can be empty.
                </div>
              </article>
              <div class="field is-grouped">
                <div class="control">
                  <button class="button is-link">Login</button>
                </div>
                <div class="control">
                  <router-link :to="{ name: 'signup' }" class="button is-link is-light">Sign Up</router-link>
                </div>
                <div class="control">
                  <router-link :to="{ name: 'password' }" class="button">I forgot my password.</router-link>
                </div>
              </div>
            </form>
          </div>
        </div>
      </div>
    </div>
  </section>
</template>

<script>
import SvgIcon from '@jamescoyle/vue-icon';
import {mdiAccount} from '@mdi/js';
import {mdiLock} from '@mdi/js';
import BaseSpinner from "@/components/ui/BaseSpinner";

export default {
  name: "UserLogin.vue",
  components: {
    SvgIcon,
    BaseSpinner
  },
  computed: {
    userIcon() {
      return mdiAccount;
    },
    passwordIcon() {
      return mdiLock;
    }
  },
  data() {
    return {
      username: '',
      password: '',
      formIsValid: true,
      isLoading: false,
      error: null
    }
  },
  methods: {
    async doLogin() {
      if (this.username === '' || this.password === '') {
        this.formIsValid = false;
        return;
      }
      this.isLoading = true;
      const actionPayload = {
        username: this.username,
        password: this.password
      };
      try {
        await this.$store.dispatch('auth/login', actionPayload);
        const redirectUrl = '/' + (this.$route.query.goto || 'aircraft');
        await this.$router.replace(redirectUrl);
      } catch (error) {
        this.error = error.message || 'Failed to authenticate, try later.';
      }
      this.isLoading = false;
    },
    handleError() {
      this.error = null;
    }
  },
}
</script>
